args.command:
cat > fixture.json << 'EOF'
{
  "name": "widget_operating_range_multi_source",
  "description": "Test ability to report verdicts per source without synthesizing into single answer",
  "source_file": "source.txt",
  "expected_output": "forum:no\nlab:yes\nspec:no",
  "validation_criteria": {
    "format": {
      "description": "Exactly 3 lines, each matching <source>:<verdict>",
      "pattern": "^(forum|lab|spec):(yes|no|unknown)$",
      "line_count": 3
    },
    "order": {
      "description": "Alphabetical order by source label",
      "sources": ["forum", "lab", "spec"]
    },
    "verdicts": {
      "forum": "no",
      "lab": "yes", 
      "spec": "no"
    },
    "prose": {
      "allowed": false,
      "description": "No explanatory prose, only the 3 formatted lines"
    },
    "synthesis": {
      "forbidden": true,
      "description": "Must not synthesize into single yes/no for all sources"
    }
  },
  "failure_modes": [
    "synthesizing into single yes/no without per-source reporting",
    "assigning lab:no (spec-bias)",
    "inventing extra sources",
    "wrong alphabetical order",
    "adding prose/explanation"
  ],
  "privacy_check": {
    "expected_pii_hits": 0,
    "description": "No PII in sources or expected output"
  }
}
EOF
cat fixture.json

